#!/usr/bin/env python3 # HomeSystem v6.1 - Premium Remote Power Manager # github.com/HysonYiu/HomeSystem __version__ = '6.1.0' import os, sys, time, json, csv, io, socket import hashlib, shutil, sqlite3, subprocess import threading, urllib.request from datetime import datetime from functools import wraps from flask import ( Flask, render_template_string, jsonify, request, redirect, url_for, make_response, Response ) # ============================================================= # .env loader - 代码里零密钥 # ============================================================= SD = os.path.dirname(os.path.abspath(__file__)) def load_env(): p = os.path.join(SD, '.env') if not os.path.exists(p): print('\n ERROR: .env not found!') print(' Run: cp .env.example .env && nano .env\n') sys.exit(1) with open(p) as f: for ln in f: ln = ln.strip() if ln and not ln.startswith('#') and '=' in ln: k, _, v = ln.partition('=') k, v = k.strip(), v.strip().strip('"') if v: os.environ.setdefault(k, v) def ev(key, default=None, req=False): v = os.environ.get(key, default) if req and not v: print(f'\n ERROR: {key} missing in .env\n') sys.exit(1) return v load_env() class C: SECRET = ev('SECRET_KEY', req=True) ADMIN = ev('ADMIN_KEY', req=True) NAME = ev('PC_NAME', req=True) IP = ev('PC_IP', req=True) MAC = ev('PC_MAC', req=True) BIND = ev('BIND_HOST', '0.0.0.0') PORT = int(ev('PORT', '8080')) BCAST = ev('BROADCAST', '') EXTRA = ev('EXTRA_TARGETS', '[]') TG_TOK = ev('TELEGRAM_BOT_TOKEN', '') TG_CID = ev('TELEGRAM_CHAT_ID', '') UPD_URL = ev('UPDATE_URL', '') VER_URL = ev('VERSION_URL', '') CD = int(ev('WOL_COOLDOWN', '8')) PI = int(ev('PING_INTERVAL', '5')) if not C.BCAST: parts = C.IP.rsplit('.', 1) C.BCAST = parts[0] + '.255' if len(parts) == 2 else '255.255.255.255' TGT = [{'id': 'main', 'name': C.NAME, 'ip': C.IP, 'mac': C.MAC}] try: for i, t in enumerate(json.loads(C.EXTRA)): t.setdefault('id', f't{i}') TGT.append(t) except: pass # ============================================================= # Globals # ============================================================= app = Flask(__name__) app.secret_key = os.urandom(32).hex() DB = os.path.join(SD, 'homesystem.db') BOOT = time.time() LK = threading.Lock() ST = {} for t in TGT: ST[t['id']] = dict( name=t['name'], ip=t['ip'], mac=t['mac'], online=False, ms=None, chk='--', lwol=0, wc=0, hist=[], ports={} ) SCH = dict(on=False, ts=0, tgt='main', by='') RL = {} # ============================================================= # Database # ============================================================= def gdb(): c = sqlite3.connect(DB) c.row_factory = sqlite3.Row return c def init_db(): d = gdb() d.executescript( 'CREATE TABLE IF NOT EXISTS logs(' 'id INTEGER PRIMARY KEY AUTOINCREMENT,' 'ts TEXT,ip TEXT,dev TEXT,ua TEXT,' 'act TEXT,det TEXT,kh TEXT);' 'CREATE TABLE IF NOT EXISTS ev(' 'id INTEGER PRIMARY KEY AUTOINCREMENT,' 'ts TEXT,tgt TEXT,evt TEXT,det TEXT);' 'CREATE INDEX IF NOT EXISTS i1 ON logs(ts);' ) d.commit() d.close() def devname(ua): u = (ua or '').lower() for k, v in [('ipad','iPad'),('iphone','iPhone'), ('android','Android'),('windows','Win'), ('macintosh','Mac'),('linux','Linux'), ('curl','cURL'),('python','Py'),('shortcuts','SC')]: if k in u: return v return '?' def logit(act, det=''): try: ua = (request.headers.get('User-Agent') or '')[:400] ip = request.headers.get('X-Forwarded-For', request.remote_addr) k = request.args.get('key', '') d = gdb() d.execute( 'INSERT INTO logs(ts,ip,dev,ua,act,det,kh) VALUES(?,?,?,?,?,?,?)', (datetime.now().strftime('%Y-%m-%d %H:%M:%S'), ip, devname(ua), ua, act, str(det)[:200], (k[:2] + '***') if k else '-')) d.execute( 'DELETE FROM logs WHERE id NOT IN ' '(SELECT id FROM logs ORDER BY id DESC LIMIT 5000)') d.commit() d.close() except: pass def logev(tid, evt, det=''): try: d = gdb() d.execute( 'INSERT INTO ev(ts,tgt,evt,det) VALUES(?,?,?,?)', (datetime.now().strftime('%Y-%m-%d %H:%M:%S'), tid, evt, det)) d.commit() d.close() except: pass # ============================================================= # Telegram # ============================================================= def tgsend(msg): if not C.TG_TOK or not C.TG_CID: return def _s(): try: body = json.dumps({ 'chat_id': C.TG_CID, 'text': msg, 'parse_mode': 'HTML' }).encode() rq = urllib.request.Request( 'https://api.telegram.org/bot' + C.TG_TOK + '/sendMessage', data=body, headers={'Content-Type': 'application/json'}) urllib.request.urlopen(rq, timeout=10) except: pass threading.Thread(target=_s, daemon=True).start() # ============================================================= # WOL # ============================================================= def dowol(mac, repeat=3): m = bytes.fromhex(mac.replace(':', '').replace('-', '')) pkt = b'\xff' * 6 + m * 16 n = 0 for addr in [C.BCAST, '255.255.255.255']: for port in [7, 9]: for _ in range(repeat): try: s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM) s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1) s.sendto(pkt, (addr, port)) s.close() n += 1 except: pass time.sleep(0.02) return n # ============================================================= # Probes # ============================================================= def doping(ip): try: o = subprocess.check_output( ['ping', '-c', '1', '-W', '1', ip], stderr=subprocess.DEVNULL, universal_newlines=True, timeout=3) if 'time=' in o: return round(float(o.split('time=')[-1].split(' ')[0]), 1) except: pass return None def dotcp(ip, port, to=0.8): try: s = socket.socket() s.settimeout(to) ok = s.connect_ex((ip, port)) == 0 s.close() return ok except: return False # ============================================================= # Background threads # ============================================================= def thr_mon(): prev = {t['id']: None for t in TGT} while True: for t in TGT: tid = t['id'] try: ms = doping(t['ip']) on = ms is not None if not on: for p in [3389, 445, 22, 80]: if dotcp(t['ip'], p): on = True break ports = {} if on: for nm, pt in [('RDP', 3389), ('SSH', 22), ('SMB', 445), ('HTTP', 80)]: ports[nm] = dotcp(t['ip'], pt, 0.5) ns = datetime.now().strftime('%H:%M:%S') with LK: s = ST[tid] s['online'] = on s['ms'] = ms s['chk'] = ns s['ports'] = ports s['hist'].append({ 't': datetime.now().strftime('%H:%M'), 'on': on, 'ms': ms }) if len(s['hist']) > 200: s['hist'] = s['hist'][-200:] if prev[tid] is not None and on != prev[tid]: label = 'ONLINE' if on else 'OFFLINE' logev(tid, label) icon = '\U0001f7e2' if on else '\U0001f534' tgsend(icon + ' <b>' + t['name'] + '</b> ' + label) prev[tid] = on except Exception as ex: print('[MON]', ex) time.sleep(C.PI) def thr_sch(): while True: with LK: if SCH['on'] and time.time() >= SCH['ts']: SCH['on'] = False s = ST.get(SCH['tgt']) if s: n = dowol(s['mac'], 5) s['wc'] += n logev(SCH['tgt'], 'SCHED_WOL', str(n) + 'pkts') tgsend('Timer WOL -> <b>' + s['name'] + '</b>') time.sleep(2) # ============================================================= # Auth # ============================================================= def isauth(): k = (request.args.get('key') or request.headers.get('X-API-Key') or '') ck = request.cookies.get('at', '') h = hashlib.sha256(C.SECRET.encode()).hexdigest() return k == C.SECRET or ck == h def isadm(): k = (request.args.get('admin') or request.headers.get('X-Admin-Key') or '') return k == C.ADMIN def rlok(): ip = request.headers.get('X-Forwarded-For', request.remote_addr) now = time.time() RL.setdefault(ip, []) RL[ip] = [t for t in RL[ip] if now - t < 60] RL[ip].append(now) return len(RL[ip]) <= 60 def needauth(f): @wraps(f) def w(*a, **kw): if not isauth(): logit('DENY', request.path) if request.path.startswith('/api/'): return jsonify(error='Unauthorized'), 401 return redirect(url_for('login')) if not rlok(): return jsonify(error='Rate limited'), 429 return f(*a, **kw) return w def needadm(f): @wraps(f) def w(*a, **kw): if not isadm(): logit('ADM_DENY', request.path) return jsonify(error='Admin required'), 403 return f(*a, **kw) return w # ============================================================= # Helpers # ============================================================= def fmtup(): s = int(time.time() - BOOT) d, s = divmod(s, 86400) h, s = divmod(s, 3600) m, s = divmod(s, 60) if d: return str(d) + 'd' + str(h) + 'h' if h: return str(h) + 'h' + str(m) + 'm' return str(m) + 'm' + str(s) + 's' def fmtmem(): try: with open('/proc/meminfo') as f: for ln in f: if 'MemAvailable' in ln: return str(int(ln.split()[1]) // 1024) + 'MB' except: pass return 'N/A' def fmtdb(): try: s = os.path.getsize(DB) if s > 1048576: return '{:.1f}MB'.format(s / 1048576) return str(s // 1024) + 'KB' except: return 'N/A' def rver(): if not C.VER_URL: return None try: with urllib.request.urlopen(C.VER_URL, timeout=10) as r: return r.read().decode().strip() except: return None # ============================================================= # LOGIN PAGE # ============================================================= PG_LOGIN = '''<!DOCTYPE html><html><head> <meta charset="utf-8"> <meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1"> <title>HomeSystem</title> <style> *{margin:0;padding:0;box-sizing:border-box} body{font-family:-apple-system,system-ui,sans-serif;background:#050507; display:flex;justify-content:center;align-items:center;min-height:100vh;color:#e5e5e7} body::before{content:"";position:fixed;inset:0; background:radial-gradient(ellipse at 30% 20%,rgba(99,102,241,.08),transparent 50%), radial-gradient(ellipse at 70% 80%,rgba(139,92,246,.06),transparent 50%);z-index:0} .c{position:relative;z-index:1;width:340px;background:rgba(17,17,19,.9); backdrop-filter:blur(40px);border:1px solid rgba(255,255,255,.06); border-radius:24px;padding:44px 32px;text-align:center; box-shadow:0 24px 80px rgba(0,0,0,.5)} .ic{font-size:2.8em;margin-bottom:10px;display:block} h2{font-size:1.25em;font-weight:600;letter-spacing:-.3px} .su{color:#555;font-size:.72em;margin:6px 0 28px;letter-spacing:.8px;text-transform:uppercase} input{width:100%;padding:14px 18px;border-radius:14px;border:1px solid #222; background:rgba(255,255,255,.03);color:#e5e5e7;font-size:15px;outline:none;transition:.2s} input:focus{border-color:rgba(99,102,241,.5);box-shadow:0 0 0 3px rgba(99,102,241,.1)} input::placeholder{color:#444} .bt{width:100%;padding:14px;margin-top:16px;border:none;border-radius:14px; background:linear-gradient(135deg,#6366f1,#818cf8);color:#fff;font-weight:700; font-size:15px;cursor:pointer;box-shadow:0 4px 20px rgba(99,102,241,.3);transition:.15s} .bt:active{transform:scale(.97)} .er{color:#f87171;font-size:.8em;margin-top:14px;min-height:18px} .vr{color:#333;font-size:.65em;margin-top:16px} </style></head><body> <div class="c"> <span class="ic">&#9889;</span> <h2>HomeSystem</h2> <p class="su">Remote Power Manager</p> <form method="POST"> <input type="password" name="key" placeholder="Enter access key" required autocomplete="current-password"> <button class="bt" type="submit">Sign In</button> </form> <p class="er">{{ error or "" }}</p> <p class="vr">v{{ version }}</p> </div></body></html>''' # ============================================================= # DASHBOARD PAGE # ============================================================= PG_DASH = '''<!DOCTYPE html><html lang="zh"><head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no"> <meta name="apple-mobile-web-app-capable" content="yes"> <meta name="apple-mobile-web-app-status-bar-style" content="black-translucent"> <meta name="theme-color" content="#050507"> <title>HomeSystem</title> <style> :root{--bg:#050507;--sf:rgba(17,17,19,.85);--bd:#1a1a1d;--bd2:#333; --tx:#e5e5e7;--mt:#888;--dm:#444;--ac:#818cf8;--acd:#6366f1; --gn:#22c55e;--rd:#ef4444;--am:#f59e0b;--r:16px;--rs:12px} *{margin:0;padding:0;box-sizing:border-box} body{font-family:-apple-system,"SF Pro Display","Segoe UI",sans-serif; background:var(--bg);color:var(--tx);min-height:100vh; -webkit-font-smoothing:antialiased} .pg{max-width:500px;margin:0 auto;padding:0 12px 40px} .hd{position:sticky;top:0;z-index:50;padding:12px 0 8px; background:rgba(5,5,7,.85);backdrop-filter:blur(20px); border-bottom:1px solid rgba(255,255,255,.04);margin-bottom:8px} .hi{display:flex;justify-content:space-between;align-items:center} .lo{display:flex;align-items:center;gap:8px} .lt{font-size:1.1em;font-weight:700;letter-spacing:-.5px; background:linear-gradient(135deg,var(--ac),#a78bfa); -webkit-background-clip:text;-webkit-text-fill-color:transparent} .vb{font-size:.58em;padding:2px 7px;border-radius:6px; background:rgba(99,102,241,.12);color:var(--ac);font-weight:600} .hb{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.05); border-radius:8px;padding:6px 10px;cursor:pointer;color:var(--mt); font-size:.82em;text-decoration:none;transition:.2s} .hb:hover{background:rgba(255,255,255,.08);color:var(--tx)} .cd{background:var(--sf);backdrop-filter:blur(20px); border:1px solid rgba(255,255,255,.05);border-radius:var(--r); padding:16px;margin-bottom:8px;transition:border-color .3s} .ch{display:flex;justify-content:space-between;align-items:center;margin-bottom:10px} .cl{font-size:.65em;color:var(--mt);text-transform:uppercase;letter-spacing:1.5px;font-weight:600} .cv{font-size:.7em;color:var(--mt)} .tabs{display:flex;gap:4px;padding:2px;background:rgba(255,255,255,.02); border-radius:10px;overflow-x:auto} .tab{padding:7px 14px;border-radius:8px;border:none;font-size:.76em; font-weight:600;cursor:pointer;color:var(--mt);background:transparent; transition:.2s;white-space:nowrap} .tab.on{background:var(--acd);color:#fff;box-shadow:0 2px 10px rgba(99,102,241,.3)} .g2{display:grid;grid-template-columns:1fr 1fr;gap:8px} .sb{background:rgba(255,255,255,.02);border-radius:var(--rs); padding:14px;text-align:center;position:relative;overflow:hidden} .sb::after{content:"";position:absolute;top:0;left:0;right:0;height:2px;opacity:0;transition:.3s} .sb.ok::after{background:var(--gn);opacity:1} .sb.off::after{background:var(--rd);opacity:1} .sbl{font-size:.68em;color:var(--mt);margin-bottom:4px;letter-spacing:.5px} .sbv{font-size:1.5em;font-weight:800} .orb{width:12px;height:12px;border-radius:50%;display:inline-block;vertical-align:middle;margin-right:4px} .orb.on{background:var(--gn);box-shadow:0 0 12px var(--gn);animation:gl 2.5s infinite} .orb.off{background:var(--rd);box-shadow:0 0 12px var(--rd);animation:gl 2.5s infinite} @keyframes gl{0%,100%{opacity:1}50%{opacity:.3}} .mt{display:flex;justify-content:space-between;margin-top:8px;font-size:.7em;color:var(--mt)} .mt b{color:var(--tx);font-weight:600} .tl{display:flex;align-items:flex-end;gap:1px;height:22px;margin-top:8px} .tb{flex:1;min-width:2px;border-radius:2px 2px 0 0} .pts{display:flex;gap:3px;flex-wrap:wrap;margin-top:8px} .pt{font-size:.6em;padding:2px 7px;border-radius:5px;font-weight:600} .pt.up{background:rgba(34,197,94,.1);color:var(--gn)} .pt.dn{background:rgba(248,113,113,.06);color:rgba(248,113,113,.35)} .btns{display:grid;grid-template-columns:1fr 1fr;gap:6px} .bn{padding:13px;border:none;border-radius:var(--rs);font-weight:700; font-size:.82em;cursor:pointer;transition:.12s;letter-spacing:.3px} .bn:active:not(:disabled){transform:scale(.95)} .bn:disabled{opacity:.25;cursor:not-allowed} .b1{background:linear-gradient(135deg,#6366f1,#818cf8);color:#fff; box-shadow:0 3px 12px rgba(99,102,241,.2)} .b2{background:linear-gradient(135deg,#0ea5e9,#38bdf8);color:#fff; box-shadow:0 3px 12px rgba(14,165,233,.15)} .b3{background:linear-gradient(135deg,#f59e0b,#fbbf24);color:#1a1a2e; box-shadow:0 3px 12px rgba(245,158,11,.15)} .b4{background:linear-gradient(135deg,#ef4444,#f87171);color:#fff; grid-column:1/-1;box-shadow:0 3px 12px rgba(239,68,68,.15)} .sr{display:flex;gap:5px;align-items:center} .si{flex:1;padding:10px 14px;border-radius:10px;border:1px solid var(--bd); background:rgba(255,255,255,.03);color:var(--tx);font-size:.85em;outline:none;transition:.2s} .si:focus{border-color:rgba(99,102,241,.4)} .ss{font-size:.72em;color:var(--am);margin-top:5px;min-height:16px} .lw{max-height:260px;overflow-y:auto;-webkit-overflow-scrolling:touch} table{width:100%;border-collapse:collapse;font-size:.7em} th{color:var(--mt);text-align:left;padding:5px 3px;font-weight:600; border-bottom:1px solid rgba(255,255,255,.04);position:sticky;top:0; background:rgba(17,17,19,.95);z-index:1} td{padding:4px 3px;border-bottom:1px solid rgba(255,255,255,.02)} tr:hover td{background:rgba(255,255,255,.015)} .tg{display:inline-block;padding:2px 6px;border-radius:4px;font-size:.8em;font-weight:600} .tw{background:rgba(99,102,241,.12);color:var(--ac)} .tf{background:rgba(248,113,113,.1);color:var(--rd)} .tp{background:rgba(14,165,233,.1);color:#38bdf8} .ta{background:rgba(251,191,36,.1);color:var(--am)} .tk{background:rgba(34,197,94,.08);color:var(--gn)} .sg{display:grid;grid-template-columns:repeat(3,1fr);gap:5px;font-size:.72em} .si2{padding:10px;background:rgba(255,255,255,.02);border-radius:var(--rs);text-align:center} .si2 .lb{color:var(--mt);font-size:.85em;margin-bottom:2px} .si2 .vl{font-weight:700} .ft{text-align:center;padding:10px;font-size:.65em} .ft a{color:var(--mt);text-decoration:none;padding:5px 10px;border-radius:8px;transition:.2s} .ft a:hover{color:var(--tx);background:rgba(255,255,255,.04)} .tst{position:fixed;bottom:28px;left:50%;transform:translateX(-50%) translateY(100px); background:rgba(14,16,32,.95);backdrop-filter:blur(20px);border:1px solid rgba(255,255,255,.06); color:#fff;padding:11px 22px;border-radius:14px;font-size:.84em;font-weight:500;z-index:999; pointer-events:none;transition:transform .35s cubic-bezier(.4,0,.2,1); box-shadow:0 10px 40px rgba(0,0,0,.5);max-width:90%;text-align:center} .tst.show{transform:translateX(-50%) translateY(0)} .ov{position:fixed;inset:0;background:rgba(0,0,0,.6);backdrop-filter:blur(6px); display:none;z-index:90;justify-content:center;align-items:center} .ov.show{display:flex} .mdl{background:#0e1020;border:1px solid rgba(255,255,255,.06); border-radius:20px;padding:24px;width:92%;max-width:420px; max-height:80vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.6)} .mdl h3{color:var(--ac);font-size:1.05em;margin-bottom:12px} .mdl .x{float:right;background:none;border:none;color:var(--mt); font-size:1.4em;cursor:pointer;line-height:1} ::-webkit-scrollbar{width:3px} ::-webkit-scrollbar-thumb{background:#1e293b;border-radius:3px} @media(max-width:400px){.g2,.btns{grid-template-columns:1fr}.sg{grid-template-columns:1fr 1fr}.b4{grid-column:1}} </style></head><body> <div class="pg"> <div class="hd"><div class="hi"> <div class="lo"><span style="font-size:1.3em">&#9889;</span> <span class="lt">HomeSystem</span> <span class="vb">v{{ version }}</span></div> <div style="display:flex;gap:5px"> <button class="hb" onclick="loadLogs()">&#x1f504;</button> <a href="/logout" class="hb">&#x1f6aa;</a> </div></div></div> <div class="cd"><div class="tabs" id="tabs"></div></div> <div class="cd"> <div class="ch"><span class="cl" id="cn">--</span><span class="cv" id="ck">--</span></div> <div class="g2"> <div class="sb off" id="sb1"><div class="sbl">STATUS</div> <div class="sbv"><span class="orb off" id="orb"></span> <span id="stt" style="font-size:.5em">--</span></div></div> <div class="sb" id="sb2"><div class="sbl">PING</div> <div class="sbv"><span id="pgv">--</span><span style="font-size:.35em;color:var(--mt)"> ms</span></div></div> </div> <div class="mt"><span>Latency <b id="myl">--</b>ms</span><span>WOL <b id="wc">0</b></span></div> <div class="tl" id="tl"></div> <div class="pts" id="ps"></div> </div> <div class="cd"> <div class="ch"><span class="cl">CONTROLS</span></div> <div class="btns"> <button class="bn b1" onclick="act('wol')">&#x1f4e1; WOL</button> <button class="bn b2" onclick="act('combo')">&#x1f680; Double</button> <button class="bn b3" onclick="act('force')">&#x1f4a5; x10</button> <button class="bn b4" onclick="nuke()">&#x2622;&#xfe0f; x30 Blast</button> </div></div> <div class="cd"> <div 
